import { forwardRef } from 'react';

export type ArvoBadgeAlertType = 'positive' | 'info' | 'neutral' | 'warning' | 'negative' | 'block';
export type ArvoBadgeAlertVariant = 'primary' | 'outline';
export type ArvoBadgeAlertSize = 'sm' | 'lg';

export interface ArvoBadgeAlertProps {
  message: string;
  type?: ArvoBadgeAlertType;
  variant?: ArvoBadgeAlertVariant;
  size?: ArvoBadgeAlertSize;
  hasIcon?: boolean;
  customIcon?: string;
  className?: string;
  role?: 'status' | 'alert';
}

const ArvoBadgeAlert = forwardRef<HTMLDivElement, ArvoBadgeAlertProps>(
  function ArvoBadgeAlert(
    {
      message,
      type = 'positive',
      variant = 'primary',
      size = 'lg',
      hasIcon = true,
      customIcon,
      className,
      role = 'status',
    },
    ref
  ) {
    const classes = [
      'arvo-bdg-alert',
      `arvo-bdg-alert--${variant}`,
      `arvo-bdg-alert--${type}`,
      `arvo-bdg-alert--${size}`,
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    const iconClasses = [
      'arvo-bdg-alert__ico',
      'o9con',
      customIcon ? `o9con-${customIcon}` : '',
    ]
      .filter(Boolean)
      .join(' ');

    return (
      <div ref={ref} role={role} className={classes}>
        {hasIcon && (
          <span className={iconClasses} aria-hidden="true" />
        )}
        <span className="arvo-bdg-alert__msg">{message}</span>
      </div>
    );
  }
);

export default ArvoBadgeAlert;
